<script setup>import{onMounted,ref}from'vue';import axios from'axios';import PageHeader from'../components/PageHeader.vue';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),data=ref({});onMounted(async()=>data.value=(await axios.get('/api/dashboard')).data);</script>
<template><PageHeader :title="data.customer_view?'Customer dashboard':'Operations overview'" :subtitle="data.customer_view?'Track orders and return to the live storefront':`Live company status for ${auth.user.name}`"/><div class="stat-grid"><article class="stat"><span>Available catalog</span><strong>{{data.products||0}}</strong><small>{{data.customer_view?'Live products':'Tracked SKUs'}}</small></article><article class="stat"><span>{{data.customer_view?'My open orders':'Sales today'}}</span><strong v-if="data.customer_view">{{data.orders_pending||0}}</strong><strong v-else>₱{{Number(data.sales_today||0).toLocaleString()}}</strong><small>{{data.customer_view?'Preparing or in delivery':'Completed POS transactions'}}</small></article><article v-if="!data.customer_view" class="stat"><span>Open orders</span><strong>{{data.orders_pending||0}}</strong><small>Reserved inventory</small></article><article v-if="!data.customer_view" class="stat"><span>Employees</span><strong>{{data.employees||0}}</strong><small>Active workforce</small></article><article v-else class="stat"><span>Shop</span><RouterLink class="btn primary" to="/">Browse products</RouterLink><small>Current inventory</small></article></div><section v-if="!data.customer_view" class="panel"><div class="panel-head"><h2>Live inventory activity</h2><span class="live">● Monitoring</span></div><div v-if="!data.latest_movements?.length" class="empty">Inventory movements will appear here in real time.</div><table v-else><thead><tr><th>Time</th><th>Product</th><th>Type</th><th>Stock change</th><th>Reserved change</th></tr></thead><tbody><tr v-for="m in data.latest_movements" :key="m.id"><td>{{new Date(m.created_at).toLocaleString()}}</td><td>#{{m.product_id}}</td><td>{{m.type}}</td><td>{{m.quantity_delta}}</td><td>{{m.reserved_delta}}</td></tr></tbody></table></section></template>
